M = [[20, 21, 19], [22, 24, 23]]

total = 0
for i in range(len(M)):
    for j in range(len(M[0])):
        total += M[i][j]

promedios = []
for fila in M:
    promedios.append(sum(fila) / len(fila))

maximo = M[0][0]
pos = (0, 0)
for i in range(len(M)):
    for j in range(len(M[0])):
        if M[i][j] > maximo:
            maximo = M[i][j]
            pos = (i, j)

print('Suma total:', total)
print('Promedios por fila:', promedios)
print('Maximo:', maximo, 'en', pos)

