lineas = ['M01;78.5', 'M02;72.0', 'M01;80.1']

datos = {}
for linea in lineas:
    codigo, valor = linea.split(';')
    valor = float(valor)
    if codigo not in datos:
        datos[codigo] = []
    datos[codigo].append(valor)

promedios = {}
for maquina, lecturas in datos.items():
    promedios[maquina] = round(sum(lecturas) / len(lecturas), 1)

mas_caliente = max(promedios, key=promedios.get)

print('Agrupado:', datos)
print('Promedios:', promedios)
print('Mas caliente:', mas_caliente)

